INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Call and meeting recording$q$, $q$Automatically records phone calls and video meetings and produces transcripts, typically available within minutes of a call ending.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$AI conversation trackers$q$, $q$Machine-learning trackers automatically flag competitor mentions, pricing discussions, objections, and next steps inside transcripts without manual tagging.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Deal and pipeline risk analytics$q$, $q$Surfaces at-risk deals by analyzing conversation patterns and engagement signals across a sales rep's pipeline.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Generative AI summaries$q$, $q$Automatically generates meeting summaries and draft follow-up emails from call transcripts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Coaching scorecards$q$, $q$Gives sales managers rep-level dashboards covering talk-time ratio, question rate, and other coachable behaviors.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$ZoomInfo data integration$q$, $q$Natively connects conversation data to ZoomInfo's contact, company, and buyer-intent data, plus Momentum pipeline and relationship views.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$CRM and video integrations$q$, $q$Connects with CRMs such as Salesforce and HubSpot, and with video platforms including Zoom, Microsoft Teams, and Google Meet.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Mature conversation-intelligence engine with well-established AI trackers for objections, competitors, and pricing talk$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Deep integration with ZoomInfo's contact and intent data for teams already on the ZoomInfo platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Generative AI meeting summaries and follow-up drafting reduce manual note-taking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Backed by a large, well-funded parent company with an established enterprise support structure$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Pricing is not public and is sold through enterprise sales, which can slow evaluation for smaller teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Best value is tied to also using other ZoomInfo products, which may not suit teams wanting a standalone tool$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$No public self-serve free trial$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Since the ZoomInfo acquisition, the product roadmap is set by ZoomInfo rather than as an independent company$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Is Chorus.ai still called Chorus.ai?$q$, $q$The product is now branded ZoomInfo Chorus. ZoomInfo acquired the company AffectLayer, Inc. (d/b/a Chorus.ai) in July 2021, and the underlying conversation-intelligence technology continues under the Chorus name inside ZoomInfo's product suite.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$What does ZoomInfo Chorus do?$q$, $q$It records, transcribes, and analyzes sales calls, video meetings, and emails using AI to surface deal risk, competitive mentions, pricing objections, and coaching opportunities for sales and customer success teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$How much does ZoomInfo Chorus cost?$q$, $q$ZoomInfo does not publish pricing. It is sold on a custom-quote basis through ZoomInfo's enterprise sales team, typically bundled with other ZoomInfo products.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Does ZoomInfo Chorus integrate with my CRM?$q$, $q$Yes. It integrates with common CRMs including Salesforce and HubSpot, plus video conferencing tools such as Zoom, Microsoft Teams, and Google Meet.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Who founded Chorus.ai?$q$, $q$Chorus.ai was founded in 2015 in San Francisco by Roy Raanani, Russell Levy, and Micha Breakstone under the legal entity AffectLayer, Inc.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Is there a free trial?$q$, $q$There is no publicly advertised self-serve free trial; prospective customers request a demo and custom quote from ZoomInfo.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Sales call coaching$q$, $q$Sales managers review AI-flagged moments from recorded calls, such as objections or pricing discussions, to coach reps on specific behaviors instead of listening to full recordings.$q$, $q$B2B sales managers and enablement teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Deal risk visibility$q$, $q$Revenue leaders use conversation and pipeline-risk analytics to spot stalled or at-risk deals before they slip, tying conversation signals directly to CRM deal records.$q$, $q$Sales leadership and RevOps$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$Unified go-to-market intelligence$q$, $q$Teams already using ZoomInfo's contact and intent data add Chorus to connect what was said on a call with who the buyer is and their broader account context.$q$, $q$Enterprise revenue teams on ZoomInfo$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chorus.ai launched in 2015 as an AI conversation-intelligence tool for B2B sales teams, recording and transcribing calls, video meetings, and emails so managers could review deals without sitting in on every conversation. ZoomInfo acquired the company in July 2021 for roughly $575 million, and the product now operates under the ZoomInfo Chorus name as part of ZoomInfo's go-to-market intelligence suite.$q$, $q$Rather than functioning as a standalone app, ZoomInfo Chorus is built to plug directly into ZoomInfo's contact, company, and intent data, giving sales and customer success teams a combined view of who they're talking to and what was actually said on the call.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform automatically records and transcribes calls and meetings, typically making transcripts available within minutes, and applies AI trackers that flag mentions of competitors, pricing, next steps, and common objections without manual tagging.$q$, $q$Generative AI features summarize meetings and draft follow-up emails from the transcript, while deal- and pipeline-risk analytics and rep-level coaching scorecards give sales managers a way to spot stalled deals and coach specific behaviors like talk-time ratio and question rate.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ZoomInfo does not publish pricing for Chorus. It is sold through ZoomInfo's enterprise sales team on a custom-quote basis, usually as part of a broader ZoomInfo contract, with pricing driven by seat count and contract length rather than a fixed public rate card.$q$, $q$There is no public self-serve signup or free trial; prospective buyers need to request a demo and quote directly from ZoomInfo.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0a2732f6-450c-43e0-9cb0-a1752605865d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Vector similarity search$q$, $q$Stores and queries high-dimensional vector embeddings to find semantically similar items for RAG, search, and recommendation use cases.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Hybrid search$q$, $q$Combines vector similarity search with full-text keyword search in a single query for more precise retrieval.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Metadata filtering$q$, $q$Filters query results using structured metadata alongside vector similarity, narrowing results by attributes like date or category.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Local-first development$q$, $q$Runs embedded inside a Python or JavaScript/TypeScript application for fast local prototyping before deploying to production.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Self-hosted deployment$q$, $q$Can be self-hosted as a standalone server under the free, open-source Apache 2.0 license with no vendor lock-in.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Chroma Cloud (serverless)$q$, $q$A managed, usage-based hosted platform built on object storage that scales compute automatically with query and write volume.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Framework integrations$q$, $q$Works with common LLM application frameworks such as LangChain and LlamaIndex, and standard embedding model providers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Genuinely free and open source (Apache 2.0) for self-hosted use, with no artificial feature gating$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Simple local-first developer experience that scales to a managed cloud service without an API rewrite$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Object-storage-based Chroma Cloud pricing is notably cheaper for storage than memory-based vector databases$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Large existing adoption (tens of thousands of open-source projects) means broad community support and integrations$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Chroma Cloud is usage-based, so costs can be harder to predict at very large scale than flat-rate plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$As a relatively young company (founded 2022), the hosted product has a shorter production track record than some incumbents$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Advanced enterprise features (dedicated infrastructure, custom SLAs) require negotiated Enterprise pricing rather than self-serve signup$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Small team size relative to larger, VC-scaled vector database competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Is Chroma free to use?$q$, $q$Yes. The open-source, self-hosted version of Chroma is free under the Apache 2.0 license. The hosted Chroma Cloud service is usage-based, starting with $5 in free credits for new accounts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$What is Chroma used for?$q$, $q$Chroma is primarily used to power retrieval-augmented generation (RAG) for LLM applications, semantic search, AI agent memory, and recommendation systems that rely on comparing vector embeddings.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Who founded Chroma?$q$, $q$Chroma was founded in 2022 by Jeff Huber, who serves as CEO, and Anton Troynikov. The company is based in San Francisco, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$How is Chroma Cloud priced?$q$, $q$Chroma Cloud bills usage-based: storage costs about $0.02 per GB per month on object storage, and compute scales with query and write volume. A Team plan is priced around $250/month with $100 of included credits.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Can I self-host Chroma instead of using Chroma Cloud?$q$, $q$Yes. Chroma's open-source core can be self-hosted as a standalone server, run embedded in an application, or migrated later to the managed Chroma Cloud service.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Retrieval-augmented generation (RAG)$q$, $q$Developers store document embeddings in Chroma and retrieve the most relevant chunks to feed into an LLM prompt, improving answer accuracy and grounding.$q$, $q$AI engineers building LLM applications$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Semantic search$q$, $q$Teams index product catalogs, support articles, or internal documents as embeddings so users can search by meaning rather than exact keyword matches.$q$, $q$Product and search teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$AI agent memory$q$, $q$Autonomous agents use Chroma to store and recall prior interactions or knowledge, giving agents persistent context across sessions.$q$, $q$Teams building AI agents and assistants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Apache 2.0 licensed","Embedded or self-hosted server deployment","No usage limits","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Chroma Cloud$q$, $q$Usage-based ($5 free credits to start)$q$, $q$Pay-as-you-go$q$, NULL, $q$["Serverless vector and hybrid search","Object-storage pricing (~$0.02/GB/mo)","Automatic compute scaling","No idle-resource charges"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Team$q$, $q$~$250/month (includes $100 usage credits)$q$, $q$Monthly$q$, NULL, $q$["Usage credits included","Team collaboration","Usage-based overage billing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Dedicated infrastructure","Configurable billing","Enterprise support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chroma is an open-source embedding database built to give AI applications a way to store, search, and retrieve vector embeddings alongside metadata and text. Founded in 2022 by Jeff Huber and Anton Troynikov and based in San Francisco, Chroma shipped its first open-source release in February 2023 and has since become one of the most widely used vector databases in the retrieval-augmented generation ecosystem.$q$, $q$The project is dual-natured: a free, Apache 2.0-licensed open-source core that developers can run locally or self-host, and Chroma Cloud, a usage-based hosted service launched in August 2025 for teams that want managed, serverless vector search at scale.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Chroma stores vector embeddings with associated metadata and supports similarity search, hybrid vector plus full-text search, and metadata filtering, making it suitable for retrieval-augmented generation, semantic search, and AI agent memory.$q$, $q$It can run embedded directly inside a Python or JavaScript application for local development, or be deployed as a self-hosted server for production, then migrated to Chroma Cloud's serverless infrastructure without changing the core API.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The open-source, self-hosted version of Chroma is free with no usage limits. Chroma Cloud uses usage-based pricing: new accounts get $5 in free credits, storage is billed at about $0.02 per GB per month on object storage, and compute scales with query and write volume.$q$, $q$A Team-tier plan runs around $250 per month with $100 of included usage credits, and Enterprise plans offer dedicated infrastructure with negotiated, configurable billing for large-scale deployments.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd5a43d0-6c12-4d8c-95e4-dbcf7e682046', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Automated visual regression testing$q$, $q$Captures pixel-level snapshots of UI components on every commit and flags visual differences against an approved baseline.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Storybook integration$q$, $q$Built by the Storybook team, with native, tightly coupled integration for testing components documented in Storybook.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$TurboSnap$q$, $q$Only re-tests components affected by a given code change, speeding up CI runs instead of re-snapshotting an entire component library.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$UI review workflow$q$, $q$Attaches visual diff reports to pull requests so designers and engineers can approve or reject changes before merging.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Interaction and accessibility testing$q$, $q$Runs interaction tests and accessibility checks alongside visual snapshots to catch functional and a11y regressions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Design tool integration$q$, $q$Connects with Figma and Sketch so design files can be compared against implemented components.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Enterprise security controls$q$, $q$SSO (SAML, OAuth) and audit logs are available on the Enterprise plan for larger organizations.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Deepest available integration with Storybook, since both are built by the same team$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Generous free tier (5,000 snapshots/month) makes it accessible for smaller and open-source projects$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$TurboSnap keeps CI run times reasonable by only re-testing affected components$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Used in production by well-known engineering teams (BBC, Mozilla, Adobe, Square)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Pricing is driven by snapshot volume, which can become expensive for large component libraries with frequent commits$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Most value is realized by teams already using Storybook; less compelling for teams without a component-driven workflow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Team and Enterprise pricing above the entry paid tier requires negotiation rather than fully transparent self-serve rates$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Focused specifically on visual/UI testing rather than full end-to-end application testing$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Do I need Storybook to use Chromatic?$q$, $q$Storybook is Chromatic's primary and most tightly integrated workflow, though Chromatic also supports visual testing via Playwright and Cypress test runners without requiring Storybook.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$How much does Chromatic cost?$q$, $q$Chromatic has a free plan with 5,000 snapshots per month. Paid plans start at $149/month for 35,000 snapshots, with a Team plan around 100,000 snapshots/month and custom Enterprise pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Who built Chromatic?$q$, $q$Chromatic was founded in 2017 by Dominic Nguyen, Tom Coleman, and Zoltan Olah, the same team that created and maintains Storybook.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$What is TurboSnap?$q$, $q$TurboSnap is a Chromatic feature that only re-tests the UI components affected by a given code change, rather than the entire component library, to keep CI runs fast.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Does Chromatic support design tool integrations?$q$, $q$Yes. Team and higher plans include Figma and Sketch integration so implemented components can be compared against design files.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Catching visual regressions in CI$q$, $q$Frontend teams add Chromatic to their CI pipeline so every pull request automatically gets a visual diff report before code is merged.$q$, $q$Frontend engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Design and engineering review$q$, $q$Designers and engineers use Chromatic's UI review workflow to approve or flag visual changes to shared component libraries and design systems.$q$, $q$Design systems teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Component library maintenance$q$, $q$Open-source and internal component library maintainers use Chromatic's free tier to catch breaking visual changes across many consumers of a shared UI library.$q$, $q$Open-source maintainers and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Free$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["5,000 snapshots/month","For open-source and small commercial projects"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Starter$q$, $q$$149/month$q$, $q$Monthly$q$, NULL, $q$["35,000 snapshots/month","Core visual testing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Team$q$, $q$Custom (negotiable overage)$q$, $q$Monthly$q$, NULL, $q$["~100,000 snapshots/month","Approval workflows","Figma and Sketch integration","Priority support","Unlimited team members"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["SSO (SAML, OAuth)","Audit logs","Advanced security controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chromatic is a cloud service for visual testing and UI review, built by the creators of Storybook. Founded in 2017 by Dominic Nguyen, Tom Coleman, and Zoltan Olah, the company grew out of their earlier work building Storybook, the open-source tool for developing and documenting UI components in isolation.$q$, $q$Chromatic automates the tedious part of catching visual bugs: it captures pixel-level snapshots of components across browsers on every commit, compares them against an approved baseline, and surfaces any differences for a designer or engineer to review inside a pull request.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes automated visual regression snapshots, interaction testing, and TurboSnap, which limits re-testing to only the components affected by a given code change to keep CI runs fast.$q$, $q$Team and Enterprise plans add approval workflows for design review, Figma and Sketch integration, unlimited team members, SSO, and audit logs, making Chromatic usable both by solo developers on open-source projects and by large frontend organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chromatic's pricing scales with monthly snapshot volume. The free plan includes 5,000 snapshots per month, suitable for smaller or open-source projects, while paid plans start at $149 per month for 35,000 snapshots.$q$, $q$The Team plan includes roughly 100,000 snapshots per month plus collaboration and design-review features, with negotiable rates for overage, and Enterprise plans add SSO and audit logging on custom pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Real-time customer health scores$q$, $q$Combines product usage, support history, NPS/survey data, and CRM data into a single score that flags churn risk or expansion opportunity.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Automated lifecycle Plays$q$, $q$Rule-based workflows trigger in-app messages, emails, or internal alerts when an account hits a risk threshold or milestone.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Journey mapping$q$, $q$Tracks customers through onboarding, adoption, and renewal stages so teams can see where accounts are in their lifecycle.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$In-app communications$q$, $q$Delivers walkthroughs, announcements, and surveys directly inside the customer's product without engineering involvement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Customer Success AI$q$, $q$Applies AI to summarize account activity and surface risk patterns for customer success managers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Renewal and Forecast Hub$q$, $q$Centralizes upcoming renewal dates and revenue forecasting for customer success and revenue teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$CRM integrations$q$, $q$Syncs usage and health data with CRMs such as Salesforce and HubSpot to keep sales and success teams aligned.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Combines usage, support, survey, and CRM data into a single actionable health score$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Automated Plays reduce manual outreach work for customer success managers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$In-app communication tools let teams engage customers without needing engineering resources$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Purpose-built for subscription and SaaS renewal/expansion workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Pricing is not public and requires a custom sales quote, which can slow evaluation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Third-party estimates suggest a meaningful annual cost, likely out of reach for very small teams or solo founders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$No advertised free trial or free tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Implementation and integration setup can require time investment for less common data sources$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$What does ChurnZero do?$q$, $q$ChurnZero is a customer success platform that tracks customer health using product usage, support, and survey data, then automates outreach and alerts to help subscription businesses reduce churn and grow accounts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$How much does ChurnZero cost?$q$, $q$ChurnZero does not publish pricing publicly. It is sold on a custom quote based on number of customers, users, data volume, and integrations; third-party sources report basic packages starting in the low five figures per year.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Who founded ChurnZero?$q$, $q$ChurnZero was founded in 2015 by You Mon Tsang (CEO) and Mark Keys (CTO).$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Does ChurnZero integrate with Salesforce and HubSpot?$q$, $q$Yes, ChurnZero integrates with common CRMs including Salesforce and HubSpot to sync customer usage and health data with sales workflows.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Is there a free trial for ChurnZero?$q$, $q$ChurnZero does not advertise a public free trial or free tier; prospective customers work with the sales team for a demo and quote.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$What is a Play in ChurnZero?$q$, $q$A Play is an automated, rule-based workflow that triggers actions such as in-app messages, emails, or internal alerts when a customer account meets a defined condition, like a risk threshold or onboarding milestone.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Churn risk management$q$, $q$Customer success teams monitor real-time health scores to identify at-risk accounts and trigger automated retention plays before renewal.$q$, $q$Customer success managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Onboarding and adoption tracking$q$, $q$Teams use journey mapping and in-app walkthroughs to guide new customers through onboarding milestones and track product adoption.$q$, $q$Customer success and onboarding teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$Renewal forecasting$q$, $q$Revenue and customer success leaders use the Renewal and Forecast Hub to track upcoming renewals and project retained revenue.$q$, $q$Customer success and revenue operations leaders$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ChurnZero is a customer success platform founded in 2015 by You Mon Tsang and Mark Keys to help subscription businesses track customer health and act on churn risk before it happens. The company is remote-first, with hubs in Washington, D.C. and Amsterdam, and has grown to roughly 148 employees.$q$, $q$The platform centers on combining product usage, support, survey, and CRM data into real-time customer health scores, then automating outreach and internal alerts based on those scores through rule-based workflows called Plays.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ChurnZero tracks customer journeys from onboarding through renewal, delivers in-app messages, walkthroughs, and surveys directly inside the customer's product, and segments accounts by usage patterns or attributes so customer success managers can prioritize their time.$q$, $q$Newer additions include Customer Success AI for summarizing account activity and flagging risk, a Renewal and Forecast Hub for tracking upcoming renewals and revenue, and Launchpad for structured customer onboarding.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ChurnZero does not publish pricing. It sells on a custom-quote basis based on the number of managed customer accounts, number of internal users, data volume, and integration needs, so prospective buyers need to contact sales for a quote.$q$, $q$There is no publicly advertised free trial or free tier; ChurnZero is positioned as a purpose-built platform for teams with a dedicated customer success function rather than a self-serve tool for very small teams.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79eab7a4-e62b-49e1-b4c9-ba1e46383aec', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Feathers post-type system$q$, $q$Supports text, photo, quote, link, video, audio, and multi-file uploader post types that can be enabled or disabled per site.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Built-in themes$q$, $q$Ships with six included themes and supports custom theme development using the Twig template engine.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$MetaWeblog XML-RPC API$q$, $q$Implements a WordPress-compatible remote publishing API, allowing posts to be published using existing blogging client software.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Minimal hosting requirements$q$, $q$Runs on PHP with either a MySQL or SQLite database, keeping server requirements lightweight compared to larger CMS platforms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$User rights model$q$, $q$Includes a permissions system for managing multiple authors and visitor accounts on a single install.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Accessible, responsive front end$q$, $q$Uses semantic HTML5 and ARIA labeling so blogs remain navigable across a broad range of devices and assistive technologies.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Completely free and open source under the BSD license, with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Very lightweight, with minimal PHP and database requirements suitable for inexpensive hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Flexible post-type (Feathers) system supports several blog formats without needing plugins$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$WordPress-compatible XML-RPC API allows remote publishing with existing blogging clients$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Requires self-hosting and basic PHP server management; there is no managed hosted version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Smaller plugin and theme ecosystem compared to large platforms like WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$No commercial support organization behind the project, only volunteer open-source maintainers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Feature set is intentionally minimal, so sites needing advanced e-commerce or membership features will need extensions or a different platform$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Is Chyrp Lite free?$q$, $q$Yes. Chyrp Lite is free, open-source software distributed under the BSD license. There are no paid plans; you self-host it on your own server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$What are the server requirements for Chyrp Lite?$q$, $q$Chyrp Lite requires a PHP-capable web server and either a MySQL or SQLite database, making its hosting requirements minimal compared to larger CMS platforms.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$How is Chyrp Lite different from the original Chyrp?$q$, $q$Chyrp Lite is a fork created in 2014 after development on the original Chyrp project (started in 2008) slowed down. It focuses on a smaller, more efficient codebase while continuing active development.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Can I publish to Chyrp Lite remotely?$q$, $q$Yes. Chyrp Lite implements a WordPress-compatible MetaWeblog XML-RPC API, so it can be used with existing blogging client software for remote publishing.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Does Chyrp Lite support multiple content types?$q$, $q$Yes, through its Feathers system, which supports text, photo, quote, link, video, audio, and multi-file uploader post types.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Personal self-hosted blogging$q$, $q$Individuals who want full control over their blog's hosting and data use Chyrp Lite as a lightweight alternative to larger CMS platforms.$q$, $q$Individual bloggers and hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Tumblelog-style microblogging$q$, $q$Site owners use the Photo, Quote, Link, Video, and Audio Feathers to build a fast-moving, multimedia-focused microblog similar to a tumblelog.$q$, $q$Creators publishing short-form, multimedia content$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["BSD licensed","Self-hosted on your own PHP server","Six built-in themes","Feathers post-type system","MetaWeblog XML-RPC API"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Chyrp Lite is a free, open-source, ultra-lightweight blogging engine written in PHP. It is a fork of the original Chyrp project (copyrighted from 2008), created in 2014 by contributor Daniel Pimley after development on the original Chyrp had slowed, with an emphasis on keeping the codebase small and efficient.$q$, $q$As a self-hosted tool distributed under the BSD license, Chyrp Lite has no company, pricing tiers, or hosted service behind it: it is maintained by volunteer open-source contributors and downloaded and installed directly onto a user's own PHP-capable web server.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Content is organized through a system of Feathers (post types) covering text, photo, quote, link, video, audio, and multi-file uploads, and Pages for static content, letting a single install function as a traditional blog, a tumblelog, or a general-purpose publishing site.$q$, $q$It ships with six built-in themes built on the Twig template engine, a MetaWeblog XML-RPC API for remote publishing compatible with WordPress clients, and a user rights model for managing multiple authors, all running on a minimal PHP plus MySQL or SQLite stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Chyrp Lite is completely free. There is no paid tier, subscription, or hosted plan; users download the open-source software and self-host it on their own server, whether shared PHP hosting, a VPS, or cloud infrastructure they manage themselves.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8635b016-4fe2-4047-a9bd-0d1adce0aa1b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Community spaces$q$, $q$Discussion spaces organized for member conversations, similar to forums or social feeds, with customizable structure per topic or group.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Courses$q$, $q$Built-in course creation with lessons and modules so creators can deliver structured educational content alongside community discussion.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Memberships and gated content$q$, $q$Native paid membership tiers and gated content let creators monetize access directly without a separate payment tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Live events$q$, $q$Hosts live events and video calls within the platform for workshops, office hours, or community meetups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$AI Agents and Co-Pilot$q$, $q$AI Agents answer member questions using a community's own content as a knowledge base, while a Co-Pilot assists with writing and repurposing content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Branded native mobile apps$q$, $q$Offers community owners a branded iOS and Android app experience under their own name, available on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Automation and integrations$q$, $q$Workflows and roughly 40 app integrations, including Zapier, Slack, Stripe, and Salesforce, automate admin tasks and connect Circle to other business tools.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Combines community, courses, memberships, events, and payments into one branded product$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Actively adding AI features (Co-Pilot, AI Agents, Workflows) rather than a static feature set$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Supports branded native mobile apps, which few community platforms offer out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Founding team's prior experience building Teachable shows in the course and monetization tooling$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$No permanent free plan; only a 14-day free trial across all tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Entry-level Professional plan lacks automation, API access, and white-labeling, often forcing an upgrade to Business$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Pricing (from $89 to $499+/month) is higher than some lighter-weight community tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Branded native mobile apps require the separate, custom-priced Plus tier$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$How much does Circle cost?$q$, $q$Circle has four annually billed plans: Professional at $89/month, Business at $199/month, Enterprise at $499/month, and a custom-priced Plus Branded App tier. All plans include a 14-day free trial.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Does Circle have a free plan?$q$, $q$No, Circle does not currently offer a permanent free plan, only a 14-day free trial with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Who founded Circle?$q$, $q$Circle was founded in early 2020 by Sid Yadav, Rudy Santino, and Andrew Guttormsen, who previously worked together on the founding team of Teachable.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Can I get a branded mobile app with Circle?$q$, $q$Yes, branded native iOS and Android apps are available, most fully through the custom-priced Plus Branded App tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$What integrations does Circle support?$q$, $q$Circle integrates with around 40 apps, including Zapier, Slack, Stripe, HubSpot, Mailchimp, WordPress, Google Sheets, and Salesforce.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$What is Circle's AI Agent feature?$q$, $q$AI Agents can automatically answer member questions using a community's own discussions, lessons, and documents as a knowledge base.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Paid creator communities$q$, $q$Creators and coaches use Circle to host a paid membership community with discussions, courses, and live events under one brand.$q$, $q$Independent creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Cohort-based and online courses$q$, $q$Educators combine Circle's course tools with community spaces so students can discuss lessons and get support alongside structured content.$q$, $q$Online educators and cohort-course creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Brand communities$q$, $q$Companies build branded customer or member communities with Circle, using automation and integrations to connect community activity to their existing tools.$q$, $q$Brands and membership businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Professional$q$, $q$$89/month$q$, $q$Annual$q$, NULL, $q$["Community spaces","Courses","Live events","No automation, API access, or white-labeling"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Business$q$, $q$$199/month$q$, $q$Annual$q$, NULL, $q$["Automation and workflows","API access","White-labeling","Everything in Professional"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Enterprise$q$, $q$$499/month$q$, $q$Annual$q$, NULL, $q$["Advanced features and support","Everything in Business"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$Plus Branded App$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Fully custom branded native mobile app","Everything in Enterprise"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Circle (Circle.so) is an all-in-one community platform founded in early 2020 by Sid Yadav, Rudy Santino, and Andrew Guttormsen, who previously worked together on the founding team of Teachable. The product publicly launched in August 2020 and is now used by more than 17,000 creators, educators, and brands.$q$, $q$Circle combines community discussion spaces, structured courses, paid memberships, live events, and native payments into a single branded platform, aiming to replace the combination of a separate community tool, course platform, and payment processor that many creators previously stitched together.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond community spaces and courses, Circle has added a growing set of AI features: a content Co-Pilot for writing and repurposing posts and lessons, AI Agents that answer member questions using a community's own content as a knowledge base, Activity Scores for tracking member engagement, and AI Workflows for automating admin tasks.$q$, $q$The platform integrates with around 40 apps including Zapier, Slack, Stripe, HubSpot, and Salesforce, and supports branded native mobile apps so communities can be offered under a creator's or brand's own name on iOS and Android.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Circle offers four annually billed plans: Professional at $89/month, Business at $199/month, Enterprise at $499/month, and a custom-priced Plus Branded App tier for a fully dedicated mobile app.$q$, $q$The entry-level Professional plan excludes automation, API access, workflows, and white-labeling, which typically pushes growing communities to the Business plan. All plans include a 14-day free trial with no credit card required, but there is no permanent free tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('80b9c68e-3f2c-4b1d-93e5-905ec8474aef', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Configurable CI/CD pipelines$q$, $q$Defines build, test, and deployment pipelines as configuration that runs automatically on code pushes or pull requests.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Broad execution environments$q$, $q$Supports Docker containers, Linux VMs, Windows, macOS, and ARM architectures for builds and tests.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Orbs$q$, $q$Reusable, shareable packages of CircleCI configuration that let teams avoid rewriting common pipeline logic like deployment steps.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Docker Layer Caching$q$, $q$Caches Docker image layers between builds, substantially speeding up builds that rely on Docker images.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Credits-based usage pricing$q$, $q$A single credits system meters compute time, storage, and certain features across plans instead of separate line-item pricing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$On-premises Server deployment$q$, $q$Offers a self-hosted, Kubernetes-based Server plan for organizations with compliance or data-residency requirements.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Enterprise access controls$q$, $q$SSO and enterprise-grade access controls are available on the Scale and Server plans for larger organizations.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Generous free tier (30,000 credits/month) supports meaningful usage before requiring payment$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Orbs and Docker Layer Caching meaningfully reduce configuration duplication and build times$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Both cloud-hosted and self-hosted (Server) options accommodate different compliance needs$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Broad execution environment support, including macOS, Windows, and ARM$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Credits-based pricing can be harder to estimate upfront than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$macOS, GPU, and larger resource classes are excluded from the Free plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Scale plan entry price (~$2,000/month) is a significant jump from the Performance tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$On-premises Server plan pricing is fully custom and not published$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Is CircleCI free?$q$, $q$Yes, CircleCI has a free plan that includes 30,000 credits per month and up to 5 active users, though it excludes macOS, GPU, and the largest resource classes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$How does CircleCI's credits pricing work?$q$, $q$CircleCI uses a universal credits system consumed by compute time and storage, priced at roughly $0.0006 per credit, with standard packs of 25,000 credits sold for $15.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Can I self-host CircleCI?$q$, $q$Yes, CircleCI offers a Server plan for on-premises, Kubernetes-based deployment with unlimited build minutes and 30 included seats, priced on a custom basis.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Who founded CircleCI?$q$, $q$CircleCI was founded in 2011 in San Francisco by Paul Biggar and Allen Rohner. Jim Rose (CEO) and Rob Zuber (CTO) joined in 2014 following the acquisition of Distiller and now lead the company.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$What are Orbs in CircleCI?$q$, $q$Orbs are reusable, shareable packages of CircleCI configuration that let teams package common pipeline logic, such as deployment steps, instead of rewriting it for every project.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$What source control platforms does CircleCI integrate with?$q$, $q$CircleCI integrates with GitHub, GitLab, and Bitbucket for source control and pull-request-triggered pipelines.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Automated testing on pull requests$q$, $q$Development teams configure CircleCI to automatically run test suites on every pull request, catching regressions before code is merged.$q$, $q$Software engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Continuous deployment$q$, $q$Teams build deployment pipelines in CircleCI that automatically ship passing builds to staging or production environments.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Compliance-driven, self-hosted CI/CD$q$, $q$Regulated organizations use CircleCI Server to run CI/CD entirely within their own infrastructure for data residency or compliance reasons.$q$, $q$Enterprises with compliance requirements$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Free$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["30,000 credits/month","Up to 5 active users","Most execution environments (excludes macOS, GPU, X-large+)"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Performance$q$, $q$From $15/month$q$, $q$Monthly$q$, NULL, $q$["30,000 credits/month","5 active users included","Additional users at $15 each","Additional credit packs available"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Scale$q$, $q$From $2,000/month$q$, $q$Monthly$q$, NULL, $q$["Custom credit volume","Unlimited builds","Enterprise access controls","SSO","24/7 support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$Server$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["On-premises, Kubernetes-based deployment","Unlimited build minutes","30 seats included"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CircleCI is a continuous integration and delivery platform founded in 2011 in San Francisco by Paul Biggar and Allen Rohner. Following CircleCI's 2014 acquisition of Distiller, Jim Rose and Rob Zuber joined as CEO and CTO and led the company's growth into a widely used CI/CD platform with roughly 358 employees today.$q$, $q$The platform automates building, testing, and deploying code through pipelines defined as configuration, supporting Docker, Linux, Windows, macOS, and ARM execution environments, and offers both a cloud-hosted service and an on-premises Server deployment.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CircleCI's Orbs let teams package and reuse pipeline configuration across projects instead of rewriting deployment logic repeatedly, and Docker Layer Caching can cut a 12-minute Docker build down to roughly 90 seconds by reusing cached image layers between runs.$q$, $q$Access controls, SSO, and priority support are available on higher tiers, while the on-premises Server plan gives organizations with strict compliance or data-residency requirements full control over their CI/CD infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CircleCI prices usage in credits, a universal unit consumed by compute time and storage, at a baseline rate of about $0.0006 per credit. The Free plan includes 30,000 credits per month and up to 5 active users.$q$, $q$The Performance plan starts at $15/month with the same base credits and users but unlocks more resource classes, extra users cost $15 each, and additional credit packs (25,000 credits for $15) can be purchased. The Scale plan starts around $2,000/month for custom credit volumes, SSO, and 24/7 support, and the Server plan offers on-premises deployment with custom pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
