INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Rooms-based architecture$q$, $q$Organizes email, forums, calendars, wikis, and blogs as navigable rooms within a single unified hierarchy instead of separate applications.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Integrated email and calendaring$q$, $q$Provides email, calendar, and contacts functionality alongside its collaboration and messaging tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Forums, mailing lists, and instant messaging$q$, $q$Supports discussion forums, mailing lists, and instant messaging within the same server.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Wiki, blog, and RSS aggregation$q$, $q$Includes wiki and blog room types, plus RSS feed aggregation, for lightweight content publishing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Multi-domain support$q$, $q$Hosts multiple domains from a single server instance, useful for supporting several organizations or communities on shared infrastructure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Standard protocol support$q$, $q$Exposes IMAP, POP3, and SMTP alongside a web interface (WebCit), so users can connect with conventional email clients or a browser.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Completely free and open source under the GPL, with no paid tiers or vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Unifies email, forums, calendars, wikis, and messaging in one self-hosted server instead of many separate tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Long, continuously maintained project history dating back decades, indicating stability of the core codebase$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Written in C for a lean, low-resource footprint suitable for modest hardware$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Requires self-hosting and server administration skills; there is no managed hosted version$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Rooms-based architecture is a distinctive but unfamiliar paradigm for users coming from mainstream email/chat tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$No commercial support organization or SLA; support relies on documentation and community forums$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Smaller active user and developer community compared to mainstream groupware platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Is Citadel free?$q$, $q$Yes. Citadel is free, open-source software distributed under the GNU General Public License, version 3. There is no paid tier or subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$What does Citadel's rooms-based architecture mean?$q$, $q$Instead of separate apps for email, forums, and calendars, Citadel organizes everything into a navigable hierarchy of rooms, where each room can function as an inbox, forum, calendar, wiki page, or blog.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$How old is the Citadel project?$q$, $q$Citadel traces back to a 1981 bulletin board system by Jeff Prothero, with a Unix-based version (Citadel/UX) emerging in 1987 that is the direct ancestor of today's software. It became open source under the GPL in 1998.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Can Citadel host multiple domains?$q$, $q$Yes, a single Citadel server instance can host multiple domains, making it usable for several organizations or communities on shared infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Does Citadel work with standard email clients?$q$, $q$Yes, Citadel supports standard protocols including IMAP, POP3, and SMTP in addition to its own WebCit web interface.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Is Citadel the same as the hedge fund Citadel?$q$, $q$No. This Citadel is unrelated to Citadel Securities or Citadel LLC, the financial firms. It is an independent open-source groupware server project hosted at citadel.org.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Self-hosted organizational groupware$q$, $q$Small organizations or communities run Citadel to get email, calendaring, and forums from one self-hosted server instead of separate tools.$q$, $q$System administrators and small organizations$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Privacy-focused community hosting$q$, $q$Privacy-conscious operators use Citadel to run their own email and discussion infrastructure without relying on third-party SaaS providers.$q$, $q$Privacy-focused individuals and communities$q$, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["GPLv3 licensed","Self-hosted on your own hardware or cloud","Email, calendaring, forums, IM, wiki, blog, RSS","Multi-domain support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Citadel is a free, open-source, self-hosted groupware server that bundles email, calendaring, forums, instant messaging, wikis, blogs, and RSS aggregation into one system. Its roots trace to a 1981 bulletin board system created by Jeff Prothero, with a Unix-based version, commonly called Citadel/UX, emerging in 1987 as the direct ancestor of the software available today.$q$, $q$The project became fully free and open source under the GPL in 1998, and the community subsequently expanded it from a BBS platform into a general-purpose groupware server. It remains a volunteer-maintained open-source project coordinated through citadel.org rather than a commercial company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Citadel's core concept is its rooms-based architecture, where a single navigable hierarchy of rooms can each act as an email inbox, discussion forum, calendar, file share, wiki page, or blog, unifying several communication tools under one system.$q$, $q$Written in C for performance and memory safety, Citadel supports standard protocols including IMAP, POP3, and SMTP alongside its WebCit web interface, and can host multiple domains from a single server instance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Citadel is completely free under the GPL version 3 license. There is no subscription, paid tier, or vendor-managed hosting option; operators download and self-host the software on infrastructure they control and maintain themselves.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fdeb2872-5b58-466b-b859-445bc95577f4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
