-- Enrichment marathon batch: Chorus.ai, Chroma, Chromatic, ChurnZero, chyrplite, Circle, CircleCI, Citadel

-- ── Chorus.ai ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-powered conversation intelligence platform that records, transcribes, and analyzes sales calls and emails; acquired by ZoomInfo in 2021 and now sold as ZoomInfo Chorus.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom enterprise quote)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Part of ZoomInfo Technologies (NASDAQ: ZI), a public company with several thousand employees$q$, company_size),
  headquarters = COALESCE($q$Vancouver, Washington, US (ZoomInfo HQ; Chorus.ai was originally founded in San Francisco, CA)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chorus.ai (ZoomInfo Chorus): Features & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$ZoomInfo Chorus (formerly Chorus.ai) records and analyzes sales calls with AI. See its features, pricing model, CRM integrations, and who it's built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chorus.ai is a conversation intelligence platform originally built for sales and customer-facing revenue teams. It records, transcribes, and analyzes phone calls, video meetings, and emails to surface deal risk, competitive mentions, pricing objections, and coaching moments. The company was founded in 2015 in San Francisco under the legal name AffectLayer, Inc. by Roy Raanani, Russell Levy, and Micha Breakstone, and traded publicly as Chorus.ai. Its core technology uses machine learning to detect talk-time ratios, question rates, sentiment shifts, and specific keyword trackers (such as competitor names, pricing terms, and next steps) inside recorded conversations, then rolls these signals up into deal-level and rep-level analytics for sales managers. In July 2021, ZoomInfo Technologies acquired Chorus.ai in a deal reported at roughly $575 million (with a final purchase consideration of about $547.4 million after a tax adjustment). Since the acquisition, the product has been rebranded and is marketed as ZoomInfo Chorus, sold as part of ZoomInfo's broader go-to-market intelligence platform rather than as a fully independent, self-serve product. The current version integrates natively with ZoomInfo's contact, company, and buyer-intent data, and includes Momentum, a pipeline and relationship-intelligence view that ties multi-channel conversations directly to CRM deal records. Core capabilities include automatic call and meeting recording with transcripts available minutes after a call ends, AI-based trackers for objections and competitive mentions, deal-risk and pipeline-risk scoring, sales coaching scorecards and dashboards, and generative-AI meeting summaries with auto-drafted follow-up emails. ZoomInfo Chorus connects to common CRMs (including Salesforce and HubSpot), video conferencing tools (Zoom, Microsoft Teams, Google Meet), and dialers, so conversation data flows into existing revenue workflows. Pricing is not published; ZoomInfo sells Chorus through its enterprise sales team on a custom-quote basis, typically bundled or discounted alongside other ZoomInfo modules, and third-party buyer resources report starting costs in the range of several thousand dollars per year with per-seat add-on pricing for larger teams, though actual costs vary by contract term and bundle. There is no public self-serve free trial. Chorus is best suited for mid-market and enterprise B2B sales organizations that already use, or plan to use, ZoomInfo's contact and intent data and want conversation intelligence tied to the same account and pipeline records, rather than teams looking for a lightweight, standalone call-recording tool. Competing standalone products in this category include Gong, Salesloft (Rhythm), and Clari Copilot. Buyers evaluating ZoomInfo Chorus should also weigh that its roadmap and support structure are now set by ZoomInfo rather than an independent company, and that meaningful cost savings typically come from bundling Chorus with other ZoomInfo modules rather than purchasing it as a standalone line item.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0a2732f6-450c-43e0-9cb0-a1752605865d';

