-- ── Chroma ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Open-source AI-native embedding and vector database for building retrieval, semantic search, and memory into LLM applications, with a usage-based hosted option called Chroma Cloud.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (open source); Chroma Cloud starts with $5 in free usage credits$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Small team (roughly 10-50 employees)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chroma: Open-Source Vector Database Features & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Chroma is an open-source embedding database for AI apps. See how it works, Chroma Cloud pricing, key features, and how it compares for RAG and search.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chroma is an open-source, AI-native embedding database (commonly called a vector database) designed to give AI applications memory and retrieval capability by storing and querying vector embeddings alongside metadata and full-text search. It was founded in 2022 by Jeff Huber (CEO) and Anton Troynikov, headquartered in San Francisco, California, and released its first public open-source version on February 14, 2023. The company raised an $18 million seed round from Astasia Myers at Quiet Capital in April 2023. Chroma is distributed under the Apache 2.0 license, which permits free commercial use, and the open-source core can be run embedded in a Python or JavaScript/TypeScript application, self-hosted as a standalone server, or deployed in a client-server configuration. According to the company, Chroma is integrated into more than 90,000 open-source codebases on GitHub and sees over 8 million downloads per month, making it one of the most widely adopted vector databases in the retrieval-augmented generation (RAG) and AI-agent ecosystem. In August 2025, Chroma launched Chroma Cloud, a serverless hosted platform built on an object-storage architecture that provides scalable vector search, hybrid search (combining vector and keyword/full-text search), and metadata filtering without the operational overhead of self-hosting. Chroma Cloud pricing is usage-based: new accounts receive $5 in free credits to start, storage is billed at roughly $0.02 per GB per month on object storage (notably lower than memory-based vector database pricing), and compute scales automatically with query and write volume so customers are not charged for idle capacity. A Team-oriented plan is priced around $250 per month and includes $100 of usage credits, while Enterprise customers get dedicated infrastructure and negotiated billing. The self-hosted, open-source version remains completely free regardless of scale. Chroma's core use cases include powering retrieval for large language model applications (RAG pipelines), semantic search over documents and knowledge bases, AI agent memory, recommendation systems, and any workload that needs to find semantically similar items by comparing vector embeddings. It integrates with common AI application frameworks such as LangChain and LlamaIndex, and supports standard embedding models from providers like OpenAI, Cohere, and open-source embedding models. Chroma targets developers and AI engineering teams building LLM-powered products who want an embedding database that is simple to start with locally (a single pip install) but can scale into a managed cloud service without switching data models or APIs. It competes with other vector database offerings such as Pinecone, Weaviate, Qdrant, and Milvus, differentiating primarily on its developer-friendly local-first workflow, open-source Apache 2.0 licensing, and object-storage-based cloud pricing.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd5a43d0-6c12-4d8c-95e4-dbcf7e682046';

