-- ── Chromatic ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud-based visual testing and UI review platform from the makers of Storybook, used to catch visual regressions in React, Vue, and Angular component libraries.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (5,000 snapshots/month); paid plans from $149/month$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Roughly 51 employees, fully remote$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US (remote-first team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chromatic: Visual Testing for Storybook, Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Chromatic is the visual testing platform built by the Storybook team. Compare plans, snapshot pricing, and key features for catching UI regressions fast.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chromatic is a cloud-based visual testing and UI review platform built by the same team that created and maintains Storybook, the widely used open-source tool for developing UI components in isolation. Chromatic operates under the legal entity Chroma Software Inc. and was founded in 2017 by Dominic Nguyen, Tom Coleman, and Zoltan Olah, a team that had previously run a web app consulting studio called Percolate Studio (founded 2012, acquired by Meteor Development Group in 2015). That consulting background led directly to building Storybook and, subsequently, Chromatic as its commercial cloud companion. Chromatic automates visual regression testing by taking pixel-level snapshots of UI components rendered in Storybook (or via Playwright/Cypress test runners) across browsers, then flags any visual differences between commits for a human to review and approve or reject. This turns UI review into a structured workflow: pull requests get a visual diff report, designers and engineers approve changes in the Chromatic UI, and approved snapshots become the new baseline. Beyond pixel diffing, Chromatic also supports interaction testing, accessibility checks, and TurboSnap, a feature that only re-tests components affected by a given code change to speed up CI runs. Pricing is based primarily on monthly snapshot volume, plus team size and collaboration features. The free tier, aimed at open-source and small commercial projects, includes 5,000 snapshots per month. Paid plans start at $149 per month for 35,000 snapshots. A Team plan adds approval workflows, Figma and Sketch integration, priority support, and unlimited team members, with around 100,000 snapshots per month and negotiable overage rates for higher volume. An Enterprise plan adds SSO (SAML, OAuth) and audit logging for larger organizations with stricter security requirements. Chromatic integrates directly with Storybook (its primary and most tightly coupled integration), and with GitHub, GitLab, and Bitbucket for pull-request-based review workflows, plus CI providers like GitHub Actions and CircleCI. It is used by frontend teams at organizations including the BBC, Mozilla, Adobe, and Square, according to the company. Chromatic is best suited for frontend engineering teams already using Storybook or component-driven development who want automated visual regression testing integrated into their pull-request workflow, rather than teams looking for full end-to-end application testing. It competes with tools such as Percy, Applitools, and Playwright's built-in visual comparison features, differentiating itself through its deep, purpose-built integration with Storybook and its snapshot-review workflow designed around component libraries and design systems. Because pricing scales with snapshot volume rather than seats, teams with large component libraries or high commit frequency should budget for the Team or Enterprise tiers rather than assuming the entry-level paid plan will cover ongoing usage as their test suite grows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4eb8addb-6a5e-46d7-8b12-ad4c212cdb1d';

