-- ── ChurnZero ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Customer success platform that tracks product usage and health scores, automates lifecycle plays, and helps subscription businesses reduce churn and grow accounts.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom enterprise quote)$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Roughly 148 employees$q$, company_size),
  headquarters = COALESCE($q$Washington, D.C., US (also operates from Amsterdam, Netherlands)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$ChurnZero: Customer Success Software Features & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$ChurnZero is a customer success platform for tracking health scores, automating lifecycle plays, and reducing churn. See features, pricing, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$ChurnZero is a customer success software platform designed to help subscription and SaaS businesses monitor customer health, automate lifecycle engagement, and reduce churn. The company was founded in 2015 by You Mon Tsang (CEO) and Mark Keys (CTO), and operates as a remote-first company with hubs in Washington, D.C. and Amsterdam. ChurnZero reports roughly 148 employees and serves customer success teams primarily at mid-market and enterprise SaaS companies. The platform's core capability is real-time customer health scoring, which combines product usage data, support ticket history, NPS and survey responses, and CRM data into a single score that flags accounts at risk of churning or ready for expansion. On top of health scores, ChurnZero provides automated 'Plays,' rule-based workflows that trigger in-app messages, emails, or internal alerts when a customer hits a risk threshold, completes an onboarding milestone, or shows expansion signals. Additional platform components include journey mapping to track customers through onboarding and renewal stages, in-app communications (walkthroughs, announcements, and surveys delivered directly inside the customer's product), segmentation tools to group accounts by attributes or behavior, and collaboration features so customer success managers, sales, and support can coordinate on shared accounts. ChurnZero has also introduced Customer Success AI, which applies AI to tasks like summarizing account activity and flagging risk patterns, along with a Renewal and Forecast Hub for tracking upcoming renewals and revenue forecasting, and a product area called Launchpad for onboarding. The platform natively tracks Net Promoter Score (NPS) and other survey types, and integrates with common CRMs (notably Salesforce and HubSpot) so usage and health data can sync back into sales and support workflows. ChurnZero does not publish pricing publicly; it is sold on a custom-quote basis that depends on factors such as number of managed customers, number of platform users, data volume, and which integrations are required. Third-party buyer resources report that a basic annual package can start in the range of roughly $12,000 to $16,000 per year plus per-user fees, though actual costs vary significantly by contract and company size, and should be confirmed directly with ChurnZero's sales team. There is no publicly advertised free trial or free tier. ChurnZero is best suited for dedicated customer success teams at subscription businesses that need a purpose-built platform to track account health and automate renewal and expansion workflows, rather than very small teams that might rely on spreadsheets or a lighter-weight tool. It competes with other customer success platforms such as Gainsight, Totango, and Vitally.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '79eab7a4-e62b-49e1-b4c9-ba1e46383aec';

