-- ── chyrplite ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Ultra-lightweight, free and open-source PHP blogging engine forked from Chyrp, built for self-hosting a simple, fast blog with themes, feathers, and extensions.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Chyrp Lite: Free Open-Source Blogging Engine$q$, seo_title),
  seo_meta_description = COALESCE($q$Chyrp Lite is a free, open-source PHP blogging engine you self-host. See its features, themes, extensions, and server requirements before installing it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Chyrp Lite is a free, open-source, ultra-lightweight blogging engine written in PHP, designed for people who want to self-host a simple blog without the overhead of a larger content management system. It is a fork of the original Chyrp project, which carries copyright dating to 2008 and was created by Alex Suraci with contributions from Arian Xhezairi and others. Arian Xhezairi became the lead developer of Chyrp in November 2010, but by 2014 active development had slowed, so contributor Daniel Pimley forked the project to continue it under the name Chyrp Lite, with an explicit focus on efficiency and a smaller codebase than the original. Chyrp Lite has been in active, ongoing development since 2014 and is distributed under the BSD license, meaning it is free to use, modify, and redistribute, including for commercial purposes. Technically, Chyrp Lite requires a PHP-capable web server and a database, supporting either MySQL or SQLite, which keeps hosting requirements minimal compared to larger PHP CMS platforms. Content is organized around a system of 'Feathers' (post types) and 'Pages.' The built-in Feathers support standard text posts as well as photo, quote, link, video, audio, and multi-file uploader post types, so a site can function as a traditional blog, a tumblelog-style microblog, or a general-purpose publishing site depending on which Feathers are enabled. Chyrp Lite ships with six built-in themes and a straightforward administration console, and its front end uses semantic HTML5 markup with ARIA labeling for accessibility across devices. Site owners can extend functionality with additional Extensions and build custom themes using the Twig template engine. For interoperability, Chyrp Lite implements a MetaWeblog XML-RPC API compatible with WordPress clients, which lets users publish to a Chyrp Lite blog remotely using existing blogging client software rather than only through the web-based admin console. It also includes a user rights and permissions model for managing multiple authors and visitor accounts. Because it has no company, subscription tiers, or hosted offering, Chyrp Lite is entirely free: there is no pricing model beyond downloading the software and self-hosting it on a server the user controls, whether shared hosting, a VPS, or cloud infrastructure. It is maintained by open-source contributors on GitHub rather than a commercial company, so there is no formal company size, headquarters, or customer support organization behind it beyond the volunteer maintainer community. Chyrp Lite is best suited for individuals, hobbyists, and small sites that want a minimal, fast, self-hosted blogging platform and are comfortable managing their own PHP hosting, rather than users looking for a fully managed, no-code blogging service like WordPress.com or Ghost's hosted offering.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8635b016-4fe2-4047-a9bd-0d1adce0aa1b';

