-- ── Circle ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$All-in-one community platform for creators and brands, combining discussion spaces, courses, paid memberships, live events, and payments in one branded product.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$89/month (Professional plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, US (remote-first team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Circle (Circle.so): Community Platform Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Circle is an all-in-one community platform for courses, memberships, and live events. Compare pricing plans, key AI features, and who it's best built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Circle (also known as Circle.so) is an all-in-one community platform built for creators, educators, and brands who want to run discussion spaces, courses, memberships, live events, and payments under a single branded product instead of stitching together separate tools. It was founded in early 2020 by Sid Yadav, Rudy Santino, and Andrew Guttormsen, a team that previously worked together on the founding team of Teachable, an online course platform that was later acquired for roughly $250 million. Circle publicly launched its product in August 2020 and has since raised about $30 million in venture funding. The company reports the platform is used by more than 17,000 creators, educators, and brands, including notable users such as Pat Flynn, Ali Abdaal, and Jay Shetty. The core product combines several previously separate categories: community spaces for discussions (organized in a way similar to forums or social feeds), structured courses with lessons and modules, paid memberships and gated content, live events and video calls, and native payment processing so creators can monetize directly on the platform. Circle has continued adding AI-driven features, including a content Co-Pilot that helps write and repurpose discussions, event recaps, and course lessons; AI Agents that can answer member questions automatically using a 'Knowledge Engine' built from a community's own discussions, lessons, and documents; Activity Scores that measure member engagement over time; and AI Workflows for automating repetitive administrative tasks. The platform integrates with roughly 40 third-party apps, including Zapier, Slack, Stripe, HubSpot, Mailchimp, WordPress, Google Sheets, and Salesforce, and supports branded native mobile apps so community owners can offer their community under their own brand on iOS and Android. Circle's pricing is structured around four tiers, billed annually. The Professional plan starts at $89 per month but does not include automation, API access, workflows, or white-labeling, which pushes many serious operators to the Business plan at $199 per month once they need those capabilities. The Enterprise plan is $499 per month and adds more advanced features and support, while a Plus Branded App tier offers a fully custom, dedicated mobile app at custom pricing. All plans include a 14-day free trial with no credit card required; there is no permanent free plan. Circle is best suited for creators, educators, coaches, and brands who want to consolidate a paid community, course delivery, and live events into one branded home rather than assembling separate tools like Discord, a course platform, and a payment processor. It competes with platforms such as Mighty Networks, Kajabi, Discord (for community specifically), and Skool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
