-- ── CircleCI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cloud and self-hosted continuous integration and delivery (CI/CD) platform for automating software builds, tests, and deployments across Linux, Windows, and macOS.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Usage-based (credits)$q$, pricing_model),
  starting_price = COALESCE($q$Free (30,000 credits/month); paid plans from $15/month$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Roughly 358 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CircleCI: CI/CD Platform Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$CircleCI is a cloud and self-hosted CI/CD platform. See free credits, paid plans, Orbs, Docker caching, and key features for automating builds and deploys.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CircleCI is a continuous integration and continuous delivery (CI/CD) platform used by software teams to automatically build, test, and deploy code. It was founded in 2011 in San Francisco by Paul Biggar and Allen Rohner. After CircleCI acquired the mobile CI tool Distiller in 2014, Jim Rose and Rob Zuber joined the company and took over as CEO and CTO respectively; Paul Biggar left the company roughly six months later but remained on the board. Under Rose and Zuber's leadership, CircleCI grew into one of the more widely used CI/CD platforms, and as of 2026 reports roughly 358 employees, remaining headquartered in San Francisco with a distributed remote workforce. The platform lets teams define build, test, and deployment pipelines as configuration files that run automatically on code pushes or pull requests, supporting execution environments including Docker containers, Linux virtual machines, Windows, macOS, and ARM architectures. Key technical features include Orbs, reusable packages of CircleCI configuration that let teams share and reuse pipeline logic (for example, standardized deployment steps) instead of rewriting configuration for every project, and Docker Layer Caching, which caches Docker image layers between builds so a build that might take 12 minutes from scratch can complete in roughly 90 seconds when the cache is warm. CircleCI structures pricing around a credits system: a universal unit consumed by compute time, storage, and certain add-on features, priced at roughly $0.0006 USD per credit as a baseline rate, with standard credit packs sold at 25,000 credits for $15. The Free plan includes 30,000 credits per month, supports up to 5 active users, and includes access to most execution environments except macOS, GPU, and the largest resource classes. The Performance plan starts at $15 per month, including the same 30,000 credits and 5 active users as the free tier but unlocking additional resource classes, with extra users priced at $15 each and additional credit packs available. The Scale plan is aimed at larger organizations, offering custom credit volumes, unlimited builds, enterprise access controls, single sign-on (SSO), and 24/7 support, starting around $2,000 per month. For organizations that need to run CI/CD entirely within their own infrastructure, CircleCI also offers a Server plan, an on-premises deployment (including Kubernetes-based installs) with unlimited build minutes, 30 included seats, and custom pricing. CircleCI integrates with GitHub, GitLab, and Bitbucket for source control, and with common deployment targets and cloud providers through its ecosystem of Orbs. It is aimed at software engineering teams of all sizes, from small teams using the free tier to enterprises running CircleCI Server on-premises for compliance or data residency reasons. Competing CI/CD platforms include GitHub Actions, GitLab CI/CD, Jenkins, and Travis CI.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cadd3f44-16e6-4e56-b77d-f1fdc0a1ac44';

