-- ── Citadel ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted groupware server providing email, calendaring, forums, instant messaging, wikis, and blogs under a distinctive rooms-based architecture.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1987, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Citadel: Free Open-Source Groupware Server$q$, seo_title),
  seo_meta_description = COALESCE($q$Citadel is a free, open-source groupware server with email, calendars, forums, and messaging. See its rooms-based architecture, features, and history.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Citadel is a free, open-source collaboration and communication platform, sometimes referred to by the disambiguating name Citadel/UX, that bundles email, calendaring and contacts, discussion forums, mailing lists, instant messaging, wikis, blogs, and RSS aggregation into a single self-hosted server. It traces its lineage back to December 1981, when Jeff Prothero created the original Citadel bulletin board system (BBS) software for 8-bit CP/M systems. In 1987, a Unix-based version of the software emerged, commonly referred to as Citadel/UX to distinguish it from other Citadel-family implementations, and this Unix lineage is the direct ancestor of the software distributed today. Citadel was widely used as a dial-up BBS platform through the 1980s and 1990s. In 1998, the software became free and open-source under the GPL-2.0-or-later license, and the developer community began expanding it from a BBS platform into a general-purpose groupware server; it is currently distributed under GPL version 3. Development and maintenance continue as a community open-source project, coordinated through the citadel.org website and an active user forum at uncensored.citadel.org, rather than by a commercial company, so there is no formal company size or single corporate headquarters behind it. Citadel's defining architectural concept is its 'rooms-based' organization: rather than folders or channels in the conventional sense, users navigate a hierarchy of rooms, each of which can function as an email inbox, a discussion forum, a calendar, a file room, a wiki page, or a blog, depending on how it is configured. This unified room model is what lets a single Citadel install cover email, group discussions, scheduling, and content publishing without separate applications. The server is written in C, which the project describes as being chosen to keep the software lean, fast, and memory-safe, and it exposes standard protocols (including IMAP, POP3, SMTP, and a web interface known as WebCit) so that users can connect with conventional email and calendar clients as well as through a browser. Citadel supports multiple domains from a single server instance, making it usable for hosting communications for several organizations or communities on shared infrastructure. Because Citadel is entirely open source and self-hosted, there is no pricing model, subscription, or paid tier: the software is downloaded and installed free of charge on hardware or cloud infrastructure that the operator controls and maintains. This also means there is no vendor-provided managed hosting, customer support contract, or SLA; support comes from project documentation and the community forum. Citadel is best suited for technically capable individuals, small organizations, or communities that want a self-hosted, all-in-one alternative to running separate email, forum, wiki, and chat servers, and who are comfortable with server administration, rather than users looking for a fully managed SaaS groupware product like Google Workspace or Microsoft 365.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fdeb2872-5b58-466b-b859-445bc95577f4';

